## 調査結果報告

### 1. 調査対象ディレクトリのファイル構成

以下の6つのGoファイルが `/Users/haru/ghq/github.com/harusame0616/ijuku-ws1/apps/api/routes/users/settings/api-keys/` に存在します：

#### ファイル1: hashed-api-key.entity.go
**内容（全文）:**
```go
package apikeys

import (
	"crypto/rand"
	"crypto/sha256"
	"encoding/base64"
	"encoding/hex"
	"errors"
	"fmt"
	"time"

	"github.com/harusame0616/ijuku/apps/api/lib/uuid"
)

type HashedApiKey struct {
	apiKeyID          string
	hashedApiKey      string
	plainApiKeySuffix string
	userID            string
	expiredAt         *time.Time
}

type NewHashedApiKeyParams struct {
	UserID    string
	ExpiredAt *time.Time
}

var ErrApiKeyCountExceedsLimit = errors.New("API key count exceeds the limit")

const ApiKeyMaxCount = 5

func NewHashedApiKey(params NewHashedApiKeyParams) (hashedApiKey HashedApiKey, plainKey string) {
	b := make([]byte, 32)

	if _, err := rand.Read(b); err != nil {
		panic(err)
	}

	plainKey = generatePlainApiKey()
	hashedApiKey = HashedApiKey{
		apiKeyID:          uuid.MustNewUuidString(),
		userID:            params.UserID,
		hashedApiKey:      getHash(plainKey),
		plainApiKeySuffix: plainKey[len(plainKey)-4:],
		expiredAt:         params.ExpiredAt,
	}

	return hashedApiKey, plainKey
}

func getHash(plain string) string {
	hash := sha256.Sum256([]byte(plain))
	return hex.EncodeToString(hash[:])
}

func generatePlainApiKey() string {
	b := make([]byte, 32)
	rand.Read(b)

	return fmt.Sprintf("jukubox_%s", base64.RawURLEncoding.EncodeToString(b))
}
```

#### ファイル2: generate-api-key.usecase.go
**内容（全文）:**
```go
package apikeys

import (
	"context"
	"fmt"
	"time"
)

type GenerateApiKeyRepository interface {
	Count(ctx context.Context, userId string) int
	Save(ctx context.Context, apiKey HashedApiKey) error
}
type UserRepository interface {
}

type GenerateApiKeyUsecase struct {
	apiKeyRepository GenerateApiKeyRepository
	userRepository   UserRepository
}

func NewGenerateApiKeyUsecase(repository GenerateApiKeyRepository) GenerateApiKeyUsecase {
	return GenerateApiKeyUsecase{apiKeyRepository: repository}
}

type GenerateApiKeyExecuteResult struct {
	Apikey string `json:"apikey"`
	Count  int    `json:"count"`
}

func (usecase *GenerateApiKeyUsecase) Execute(ctx context.Context, userId string, expiredAt *time.Time) (GenerateApiKeyExecuteResult, error) {
	// 不変条件が上限チェックのみのため、Usecase 層でチェックする
	// 複数の不変条件が加わる場合は UserApiKeys ドメインコレクションへの昇格を検討する
	userApiKeyCount := usecase.apiKeyRepository.Count(ctx, userId)
	if userApiKeyCount >= ApiKeyMaxCount {
		return GenerateApiKeyExecuteResult{}, ErrApiKeyCountExceedsLimit
	}

	hashedApiKey, plainApiKey := NewHashedApiKey(NewHashedApiKeyParams{
		UserID:    userId,
		ExpiredAt: expiredAt,
	})

	if err := usecase.apiKeyRepository.Save(ctx, hashedApiKey); err != nil {
		fmt.Errorf("error %v", err)
		return GenerateApiKeyExecuteResult{}, err
	}

	return GenerateApiKeyExecuteResult{
		Apikey: plainApiKey,
		Count:  userApiKeyCount,
	}, nil
}
```

#### ファイル3: api-key.sqrc-repository.go
**内容（全文）:**
```go
package apikeys

import (
	"context"

	"github.com/harusame0616/ijuku/apps/api/internal/db"
	"github.com/jackc/pgx/v5/pgtype"
)

type sqrcQueries interface {
	InsertApiKey(ctx context.Context, arg db.InsertApiKeyParams) error
	CountApiKeyByUserID(ctx context.Context, userid pgtype.UUID) (int64, error)
}

type ApiKeySqrcRepository struct {
	queries sqrcQueries
}

func NewApiKeySqrcRepository(sqrc sqrcQueries) ApiKeySqrcRepository {
	return ApiKeySqrcRepository{queries: sqrc}
}

func (repo ApiKeySqrcRepository) Count(ctx context.Context, userId string) int {
	var userID pgtype.UUID
	if err := userID.Scan(userId); err != nil {
		return 0
	}
	count, err := repo.queries.CountApiKeyByUserID(ctx, userID)
	if err != nil {
		return 0
	}
	return int(count)
}

func (repo ApiKeySqrcRepository) Save(ctx context.Context, apiKey HashedApiKey) error {
	var apikeyID pgtype.UUID
	var userID pgtype.UUID

	if err := apikeyID.Scan(apiKey.apiKeyID); err != nil {
		return err
	}
	if err := userID.Scan(apiKey.userID); err != nil {
		return err
	}

	var expiredAt pgtype.Timestamptz
	if apiKey.expiredAt == nil {
		expiredAt = pgtype.Timestamptz{
			InfinityModifier: pgtype.Infinity,
			Valid:            true,
		}
	} else {
		expiredAt = pgtype.Timestamptz{
			Time:  *apiKey.expiredAt,
			Valid: true,
		}
	}

	return repo.queries.InsertApiKey(ctx, db.InsertApiKeyParams{
		ApikeyID:       apikeyID,
		KeyHash:        apiKey.hashedApiKey,
		UserID:         userID,
		KeyPlainSuffix: apiKey.plainApiKeySuffix,
		ExpiredAt:      expiredAt,
	})
}
```

#### ファイル4: hashed-api-key.entity.server_test.go
**内容（全文）:**
```go
package apikeys

import (
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
)

func TestHashedApiKeyEntitySmall(t *testing.T) {
	t.Run("NewHashedApiKey: plain key が正しいフォーマットで生成される", func(t *testing.T) {
		_, plainKey := NewHashedApiKey(NewHashedApiKeyParams{UserID: "user-id"})

		assert.Regexp(t, `^jukubox_[A-Za-z0-9\-_]{43}$`, plainKey)
	})

	t.Run("NewHashedApiKey: HashedApiKey フィールドが SHA-256 hex 形式になっている", func(t *testing.T) {
		hashed, _ := NewHashedApiKey(NewHashedApiKeyParams{UserID: "user-id"})

		assert.Regexp(t, `^[0-9a-f]{64}$`, hashed.hashedApiKey)
	})

	t.Run("NewHashedApiKey: HashedApiKey が plain key のハッシュと一致する", func(t *testing.T) {
		hashed, plainKey := NewHashedApiKey(NewHashedApiKeyParams{UserID: "user-id"})

		assert.Equal(t, getHash(plainKey), hashed.hashedApiKey)
	})

	t.Run("NewHashedApiKey: PlainApiKeySuffix が plain key の末尾4文字になっている", func(t *testing.T) {
		hashed, plainKey := NewHashedApiKey(NewHashedApiKeyParams{UserID: "user-id"})

		assert.Equal(t, plainKey[len(plainKey)-4:], hashed.plainApiKeySuffix)
	})

	t.Run("NewHashedApiKey: UserID が引数の値になっている", func(t *testing.T) {
		const userID = "test-user-id"
		hashed, _ := NewHashedApiKey(NewHashedApiKeyParams{UserID: userID})

		assert.Equal(t, userID, hashed.userID)
	})

	t.Run("NewHashedApiKey: ExpiredAt が nil の場合は nil になっている", func(t *testing.T) {
		hashed, _ := NewHashedApiKey(NewHashedApiKeyParams{UserID: "user-id", ExpiredAt: nil})

		assert.Nil(t, hashed.expiredAt)
	})

	t.Run("NewHashedApiKey: ExpiredAt が指定された場合はその値になっている", func(t *testing.T) {
		expiredAt := time.Date(2030, 1, 1, 0, 0, 0, 0, time.UTC)
		hashed, _ := NewHashedApiKey(NewHashedApiKeyParams{UserID: "user-id", ExpiredAt: &expiredAt})

		assert.Equal(t, &expiredAt, hashed.expiredAt)
	})

	t.Run("NewHashedApiKey: ApiKeyID が UUID 形式で生成される", func(t *testing.T) {
		hashed, _ := NewHashedApiKey(NewHashedApiKeyParams{UserID: "user-id"})

		assert.Regexp(t, `^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$`, hashed.apiKeyID)
	})

	t.Run("NewHashedApiKey: 異なる呼び出しで異なる plain key が生成される", func(t *testing.T) {
		_, plainKey1 := NewHashedApiKey(NewHashedApiKeyParams{UserID: "user-id"})
		_, plainKey2 := NewHashedApiKey(NewHashedApiKeyParams{UserID: "user-id"})

		assert.NotEqual(t, plainKey1, plainKey2)
	})
